import {
  Box,
  Typography,
  Button,
  Card,
  CardContent,
  Grid,
  List,
  ListItem,
  ListItemText,
  Divider,
} from "@mui/material";

const projects = [
  { id: 1, name: "Project A" },
  { id: 2, name: "Project B" },
];

export default function ManagerDashboard() {
  return (
    <Box sx={{ display: "flex", height: "100vh" }}>
      {/* 🔹 Sidebar */}
      <Box
        sx={{
          width: 220,
          bgcolor: "#1e293b",
          color: "#fff",
          p: 2,
          display: "flex",
          flexDirection: "column",
        }}
      >
        <Typography variant="h6" mb={2}>
          UserName
        </Typography>

        <Divider sx={{ bgcolor: "#555", mb: 2 }} />

        <List>
          <ListItem button>
            <ListItemText primary="Profile Settings" />
          </ListItem>
          <ListItem button>
            <ListItemText primary="Projects" />
          </ListItem>
          <ListItem button>
            <ListItemText primary="Logout" />
          </ListItem>
        </List>
      </Box>

      {/* 🔹 Main Content */}
      <Box sx={{ flex: 1, p: 4, bgcolor: "#f1f5f9" }}>
        <Typography variant="h5" fontWeight="bold" mb={3}>
          Projects
        </Typography>

        <Grid container spacing={4}>
          {projects.map((project) => (
            <Grid item xs={12} sm={6} md={4} key={project.id}>
              <Card
                sx={{
                  borderRadius: 3,
                  boxShadow: 3,
                  p: 2,
                  transition: "0.3s",
                  "&:hover": {
                    transform: "translateY(-5px)",
                    boxShadow: 6,
                  },
                }}
              >
                <CardContent>
                  {/* Project Name */}
                  <Typography fontWeight="bold" mb={1}>
                    {project.name}
                  </Typography>

                  {/* Preview Box */}
                  <Box
                    sx={{
                      height: 150,
                      border: "2px dashed #999",
                      borderRadius: 2,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      mb: 2,
                      color: "#666",
                      fontSize: 14,
                    }}
                  >
                    Preview Image / BIM Thumbnail
                  </Box>

                  {/* View Button */}
                  <Button
                    fullWidth
                    variant="outlined"
                    sx={{
                      borderRadius: 3,
                      textTransform: "none",
                    }}
                    onClick={() => alert(project.name)}
                  >
                    View
                  </Button>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Box>
    </Box>
  );
}
